const _astro_dataLayerContent = [["Map", 1, 2, 508, 509], "duas", ["Map", 3, 4, 14, 15, 24, 25, 34, 35, 44, 45, 53, 54, 62, 63, 71, 72, 81, 82, 89, 90, 99, 100, 107, 108, 115, 116, 125, 126, 134, 135, 144, 145, 153, 154, 162, 163, 171, 172, 181, 182, 190, 191, 199, 200, 208, 209, 215, 216, 224, 225, 234, 235, 243, 244, 252, 253, 261, 262, 270, 271, 279, 280, 288, 289, 297, 298, 306, 307, 315, 316, 324, 325, 334, 335, 343, 344, 353, 354, 362, 363, 371, 372, 380, 381, 389, 390, 398, 399, 407, 408, 417, 418, 426, 427, 435, 436, 444, 445, 453, 454, 462, 463, 471, 472, 480, 481, 490, 491, 499, 500], "dua-1", { id: 3, data: 5, filePath: 13 }, { title: 6, titleAr: 7, category: 8, arabic: 9, transliteration: 10, translation: 11, reference: 12 }, "Dua Before Sleeping", "دعاء النوم", "Daily", "بِاسْمِكَ اللَّهُمَّ أَمُوتُ وَأَحْيَا", "Bismika Allahumma amutu wa ahya", "In Your name, O Allah, I die and I live.", "Bukhari 6312", "src/data/duas.json", "dua-10", { id: 14, data: 16, filePath: 13 }, { title: 17, titleAr: 18, category: 19, arabic: 20, transliteration: 21, translation: 22, reference: 23 }, "Dua for Patience", "دعاء الصبر", "Hardship", "رَبَّنَا أَفْرِغْ عَلَيْنَا صَبْرًا وَثَبِّتْ أَقْدَامَنَا وَانصُرْنَا عَلَى الْقَوْمِ الْكَافِرِينَ", "Rabbana afrigh 'alayna sabran wa thabbit aqdamana wansurna 'alal-qawmil-kafireen", "Our Lord, pour upon us patience and plant firmly our feet and give us victory over the disbelieving people.", "Quran 2:250", "dua-11", { id: 24, data: 26, filePath: 13 }, { title: 27, titleAr: 28, category: 29, arabic: 30, transliteration: 31, translation: 32, reference: 33 }, "Dua for Protection", "دعاء الحفظ", "Protection", "بِسْمِ اللَّهِ الَّذِي لاَ يَضُرُّ مَعَ اسْمِهِ شَيْءٌ فِي الأَرْضِ وَلاَ فِي السَّمَاءِ وَهُوَ السَّمِيعُ الْعَلِيمُ", "Bismillahil-lathee la yadurru ma'asmihi shay'un fil-ardi wa la fis-sama'i wa huwas-samee'ul-'aleem", "In the name of Allah with whose name nothing is harmed on earth nor in the heavens and He is the All-Hearing, the All-Knowing.", "Abu Dawud 5088", "dua-12", { id: 34, data: 36, filePath: 13 }, { title: 37, titleAr: 38, category: 39, arabic: 40, transliteration: 41, translation: 42, reference: 43 }, "Dua for Knowledge", "دعاء العلم", "Knowledge", "رَبِّ زِدْنِي عِلْمًا", "Rabbi zidnee 'ilma", "My Lord, increase me in knowledge.", "Quran 20:114", "dua-13", { id: 44, data: 46, filePath: 13 }, { title: 47, titleAr: 48, category: 19, arabic: 49, transliteration: 50, translation: 51, reference: 52 }, "Dua When in Distress", "دعاء الكرب", "لاَ إِلَهَ إِلاَّ اللَّهُ الْعَظِيمُ الْحَلِيمُ، لاَ إِلَهَ إِلاَّ اللَّهُ رَبُّ الْعَرْشِ الْعَظِيمِ، لاَ إِلَهَ إِلاَّ اللَّهُ رَبُّ السَّمَاوَاتِ وَرَبُّ الأَرْضِ وَرَبُّ الْعَرْشِ الْكَرِيمِ", "La ilaha illallahul-'atheemul-haleem, la ilaha illallahu rabbul-'arshil-'atheem, la ilaha illallahu rabbus-samawati wa rabbul-ardi wa rabbul-'arshil-kareem", "There is no god but Allah the Mighty, the Forbearing. There is no god but Allah, Lord of the mighty throne. There is no god but Allah, Lord of the heavens and Lord of the earth and Lord of the noble throne.", "Bukhari 6346", "dua-14", { id: 53, data: 55, filePath: 13 }, { title: 56, titleAr: 57, category: 8, arabic: 58, transliteration: 59, translation: 60, reference: 61 }, "Dua for a Good End", "دعاء حسن الخاتمة", "يَا مُقَلِّبَ الْقُلُوبِ ثَبِّتْ قَلْبِي عَلَى دِينِكَ", "Ya Muqallibal-quloob thabbit qalbee 'ala deenik", "O Turner of hearts, keep my heart firm upon Your religion.", "Tirmidhi 3522", "dua-15", { id: 62, data: 64, filePath: 13 }, { title: 65, titleAr: 66, category: 8, arabic: 67, transliteration: 68, translation: 69, reference: 70 }, "Dua for Provision", "دعاء الرزق", "اللَّهُمَّ إِنِّي أَسْأَلُكَ عِلْمًا نَافِعًا، وَرِزْقًا طَيِّبًا، وَعَمَلًا مُتَقَبَّلًا", "Allahumma innee as'aluka 'ilman nafi'an, wa rizqan tayyiban, wa 'amalan mutaqabbalan", "O Allah, I ask You for beneficial knowledge, good provision, and acceptable deeds.", "Ibn Majah 925", "dua-16", { id: 71, data: 73, filePath: 13 }, { title: 74, titleAr: 75, category: 76, arabic: 77, transliteration: 78, translation: 79, reference: 80 }, "Morning Remembrance", "ذكر الصباح", "Morning & Evening", "أَصْبَحْنَا وَأَصْبَحَ الْمُلْكُ لِلَّهِ، وَالْحَمْدُ لِلَّهِ، لاَ إِلَهَ إِلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ", "Asbahna wa asbahal-mulku lillah, walhamdu lillah, la ilaha illallahu wahdahu la shareeka lah", "We have reached the morning and at this very time the whole kingdom belongs to Allah. All praise is for Allah. None has the right to be worshipped except Allah, alone, without any partner.", "Muslim 2723", "dua-17", { id: 81, data: 83, filePath: 13 }, { title: 84, titleAr: 85, category: 76, arabic: 86, transliteration: 87, translation: 88, reference: 80 }, "Evening Remembrance", "ذكر المساء", "أَمْسَيْنَا وَأَمْسَى الْمُلْكُ لِلَّهِ، وَالْحَمْدُ لِلَّهِ، لاَ إِلَهَ إِلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ", "Amsayna wa amsal-mulku lillah, walhamdu lillah, la ilaha illallahu wahdahu la shareeka lah", "We have reached the evening and at this very time the whole kingdom belongs to Allah. All praise is for Allah. None has the right to be worshipped except Allah, alone, without any partner.", "dua-18", { id: 89, data: 91, filePath: 13 }, { title: 92, titleAr: 93, category: 94, arabic: 95, transliteration: 96, translation: 97, reference: 98 }, "Entering the Mosque", "دعاء دخول المسجد", "Mosque", "اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ", "Allahum-maftah lee abwaba rahmatika", "O Allah, open the gates of Your mercy for me.", "Muslim 713", "dua-19", { id: 99, data: 101, filePath: 13 }, { title: 102, titleAr: 103, category: 94, arabic: 104, transliteration: 105, translation: 106, reference: 98 }, "Leaving the Mosque", "دعاء الخروج من المسجد", "اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَ", "Allahumma innee as'aluka min fadlika", "O Allah, I ask You from Your favour.", "dua-2", { id: 107, data: 109, filePath: 13 }, { title: 110, titleAr: 111, category: 8, arabic: 112, transliteration: 113, translation: 114, reference: 12 }, "Dua Upon Waking Up", "دعاء الاستيقاظ", "الحَمْدُ لِلَّهِ الَّذِي أَحْيَانَا بَعْدَ مَا أَمَاتَنَا وَإِلَيْهِ النُّشُورُ", "Alhamdu lillahil-lathee ahyana ba'da ma amatana wa ilayhin-nushur", "All praise is for Allah who gave us life after having taken it from us and unto Him is the resurrection.", "dua-20", { id: 115, data: 117, filePath: 13 }, { title: 118, titleAr: 119, category: 120, arabic: 121, transliteration: 122, translation: 123, reference: 124 }, "After Adhan", "دعاء بعد الأذان", "Prayer", "اللَّهُمَّ رَبَّ هَذِهِ الدَّعْوَةِ التَّامَّةِ، وَالصَّلاَةِ الْقَائِمَةِ، آتِ مُحَمَّدًا الْوَسِيلَةَ وَالْفَضِيلَةَ، وَابْعَثْهُ مَقَامًا مَحْمُودًا الَّذِي وَعَدْتَهُ", "Allaahumma Rabba haathid-da'watit-taammah, wassalaatil-qaa'imah, aati Muhammadanil-waseelata walfadeelah, wab'athhu maqaamam mahmoodanil-lathee wa'adtah", "O Allah, Lord of this perfect call and established prayer, grant Muhammad the intercession and favour, and raise him to the praised station that You have promised him.", "Bukhari 614", "dua-21", { id: 125, data: 127, filePath: 13 }, { title: 128, titleAr: 129, category: 120, arabic: 130, transliteration: 131, translation: 132, reference: 133 }, "Between Adhan and Iqamah", "دعاء بين الأذان والإقامة", "اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَافِيَةَ فِي الدُّنْيَا وَالآخِرَةِ", "Allahumma innee as'alukal-'aafiyata fid-dunya wal-aakhirah", "O Allah, I ask You for wellbeing in this world and the Hereafter.", "Abu Dawud 5052", "dua-22", { id: 134, data: 136, filePath: 13 }, { title: 137, titleAr: 138, category: 139, arabic: 140, transliteration: 141, translation: 142, reference: 143 }, "Before Wudu (Ablution)", "دعاء قبل الوضوء", "Worship", "بِسْمِ اللَّهِ", "Bismillah", "In the name of Allah.", "Abu Dawud 101", "dua-23", { id: 144, data: 146, filePath: 13 }, { title: 147, titleAr: 148, category: 139, arabic: 149, transliteration: 150, translation: 151, reference: 152 }, "After Wudu (Ablution)", "دعاء بعد الوضوء", "أَشْهَدُ أَنْ لاَ إِلَهَ إِلاَّ اللَّهُ وَحْدَهُ لاَ شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ", "Ash-hadu an la ilaha illallahu wahdahu la shareeka lah, wa ash-hadu anna Muhammadan 'abduhu wa rasooluhu", "I bear witness that none has the right to be worshipped except Allah, alone without partner, and I bear witness that Muhammad is His slave and messenger.", "Muslim 234", "dua-24", { id: 153, data: 155, filePath: 13 }, { title: 156, titleAr: 157, category: 8, arabic: 158, transliteration: 159, translation: 160, reference: 161 }, "Before Entering Toilet", "دعاء دخول الخلاء", "بِسْمِ اللَّهِ، اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْخُبْثِ وَالْخَبَائِثِ", "Bismillah, Allahumma innee a'oothu bika minal-khubthi wal-khaba'ith", "In the name of Allah. O Allah, I seek refuge in You from the male and female evil jinn.", "Bukhari 142", "dua-25", { id: 162, data: 164, filePath: 13 }, { title: 165, titleAr: 166, category: 8, arabic: 167, transliteration: 168, translation: 169, reference: 170 }, "After Leaving Toilet", "دعاء الخروج من الخلاء", "غُفْرَانَكَ", "Ghufraanak", "I seek Your forgiveness.", "Tirmidhi 7", "dua-26", { id: 171, data: 173, filePath: 13 }, { title: 174, titleAr: 175, category: 176, arabic: 177, transliteration: 178, translation: 179, reference: 180 }, "When It Rains", "دعاء نزول المطر", "Nature", "اللَّهُمَّ صَيِّبًا نَافِعًا", "Allahumma sayyiban naafi'aa", "O Allah, (let it be) a beneficial rain.", "Bukhari 1032", "dua-27", { id: 181, data: 183, filePath: 13 }, { title: 184, titleAr: 185, category: 176, arabic: 186, transliteration: 187, translation: 188, reference: 189 }, "After Rain", "دعاء بعد المطر", "مُطِرْنَا بِفَضْلِ اللَّهِ وَرَحْمَتِهِ", "Mutirna bifadlillahi wa rahmatihi", "We have been given rain by the grace and mercy of Allah.", "Bukhari 846", "dua-28", { id: 190, data: 192, filePath: 13 }, { title: 193, titleAr: 194, category: 176, arabic: 195, transliteration: 196, translation: 197, reference: 198 }, "When Seeing the New Moon", "دعاء رؤية الهلال", "اللَّهُمَّ أَهِلَّهُ عَلَيْنَا بِالْيُمْنِ وَالإِيمَانِ، وَالسَّلاَمَةِ وَالإِسْلاَمِ، رَبِّي وَرَبُّكَ اللَّهُ", "Allahumma ahillahu 'alayna bil-yumni wal-eeman, was-salaamati wal-islam, rabbee wa rabbukal-lahu", "O Allah, let this moon appear on us with prosperity and faith, with safety and Islam. My Lord and your Lord is Allah.", "Tirmidhi 3454", "dua-29", { id: 199, data: 201, filePath: 13 }, { title: 202, titleAr: 203, category: 8, arabic: 204, transliteration: 205, translation: 206, reference: 207 }, "When Looking in the Mirror", "دعاء النظر في المرآة", "اللَّهُمَّ أَنْتَ حَسَّنْتَ خَلْقِي فَحَسِّنْ خُلُقِي", "Allahumma anta hassanta khalqee fahassin khuluqee", "O Allah, just as You have made my outward appearance beautiful, make my character beautiful too.", "Ahmad 3823", "dua-3", { id: 208, data: 210, filePath: 13 }, { title: 211, titleAr: 212, category: 213, arabic: 140, transliteration: 141, translation: 142, reference: 214 }, "Dua Before Eating", "دعاء قبل الطعام", "Food", "Abu Dawud 3767", "dua-30", { id: 215, data: 217, filePath: 13 }, { title: 218, titleAr: 219, category: 8, arabic: 220, transliteration: 221, translation: 222, reference: 223 }, "When Wearing New Clothes", "دعاء لبس الثوب الجديد", "اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ كَسَوْتَنِيهِ، أَسْأَلُكَ مِنْ خَيْرِهِ وَخَيْرِ مَا صُنِعَ لَهُ، وَأَعُوذُ بِكَ مِنْ شَرِّهِ وَشَرِّ مَا صُنِعَ لَهُ", "Allahumma lakal-hamdu anta kasawtaneehi, as'aluka min khayrihi wa khayri ma suni'a lah, wa a'oothu bika min sharrihi wa sharri ma suni'a lah", "O Allah, all praise is for You. You have clothed me with it. I ask You for its good and the good of what it was made for, and I seek refuge in You from its evil and the evil of what it was made for.", "Tirmidhi 1767", "dua-31", { id: 224, data: 226, filePath: 13 }, { title: 227, titleAr: 228, category: 229, arabic: 230, transliteration: 231, translation: 232, reference: 233 }, "Dua for Good Health", "دعاء العافية", "Health", "اللَّهُمَّ إِنِّي أَسْأَلُكَ الْعَفْوَ وَالْعَافِيَةَ فِي الدُّنْيَا وَالآخِرَةِ", "Allahumma innee as'alukal-'afwa wal-'aafiyata fid-dunya wal-aakhirah", "O Allah, I ask You for pardon and wellbeing in this world and the Hereafter.", "Ibn Majah 3871", "dua-32", { id: 234, data: 236, filePath: 13 }, { title: 237, titleAr: 238, category: 229, arabic: 239, transliteration: 240, translation: 241, reference: 242 }, "When Visiting the Sick", "دعاء زيارة المريض", "لاَ بَأْسَ طَهُورٌ إِنْ شَاءَ اللَّهُ", "La ba'sa, taahoorun in shaa'Allah", "No worry, it is a purification, if Allah wills.", "Bukhari 3616", "dua-33", { id: 243, data: 245, filePath: 13 }, { title: 246, titleAr: 247, category: 229, arabic: 248, transliteration: 249, translation: 250, reference: 251 }, "When Feeling Pain", "دعاء الألم", "بِسْمِ اللَّهِ، أَعُوذُ بِاللَّهِ وَقُدْرَتِهِ مِنْ شَرِّ مَا أَجِدُ وَأُحَاذِرُ", "Bismillah, a'oothu billahi wa qudratihi min sharri ma ajidu wa uhaathir", "In the name of Allah. I seek refuge in Allah and His power from the evil of what I feel and worry about.", "Muslim 2202", "dua-34", { id: 252, data: 254, filePath: 13 }, { title: 255, titleAr: 256, category: 19, arabic: 257, transliteration: 258, translation: 259, reference: 260 }, "Dua for Ease in Difficulty", "دعاء التيسير", "اللَّهُمَّ لاَ سَهْلَ إِلاَّ مَا جَعَلْتَهُ سَهْلًا، وَأَنْتَ تَجْعَلُ الْحَزْنَ إِذَا شِئْتَ سَهْلًا", "Allahumma la sahla illa ma ja'altahu sahla, wa anta taj'alul-hazna itha shi'ta sahla", "O Allah, there is no ease other than what You make easy. If You please, You ease sorrow/difficulty.", "Ibn Hibban 2427", "dua-35", { id: 261, data: 263, filePath: 13 }, { title: 264, titleAr: 265, category: 139, arabic: 266, transliteration: 267, translation: 268, reference: 269 }, "Dua for a Good Hereafter", "دعاء حسنة في الآخرة", "رَبَّنَا آتِنَا فِي الدُّنْيَا حَسَنَةً وَفِي الآخِرَةِ حَسَنَةً وَقِنَا عَذَابَ النَّارِ", "Rabbana aatina fid-dunya hasanatan wa fil-aakhirati hasanatan wa qina 'athaaban-naar", "Our Lord, give us in this world that which is good and in the Hereafter that which is good, and protect us from the torment of the Fire.", "Quran 2:201", "dua-36", { id: 270, data: 272, filePath: 13 }, { title: 273, titleAr: 274, category: 39, arabic: 275, transliteration: 276, translation: 277, reference: 278 }, "Dua for Beneficial Knowledge", "دعاء العلم النافع", "اللَّهُمَّ انْفَعْنِي بِمَا عَلَّمْتَنِي، وَعَلِّمْنِي مَا يَنْفَعُنِي، وَزِدْنِي عِلْمًا", "Allahum-man-fa'nee bima 'allamtanee, wa 'allimnee ma yanfa'umee, wa zidnee 'ilma", "O Allah, benefit me with what You have taught me, teach me what will benefit me, and increase me in knowledge.", "Tirmidhi 3599", "dua-37", { id: 279, data: 281, filePath: 13 }, { title: 282, titleAr: 283, category: 39, arabic: 284, transliteration: 285, translation: 286, reference: 287 }, "Dua Before Studying", "دعاء قبل الدراسة", "رَبِّ اشْرَحْ لِي صَدْرِي وَيَسِّرْ لِي أَمْرِي وَاحْلُلْ عُقْدَةً مِنْ لِسَانِي يَفْقَهُوا قَوْلِي", "Rabbish-rah lee sadree, wa yassir lee amree, wahlul 'uqdatan min lisanee, yafqahoo qawlee", "My Lord, expand for me my chest, ease for me my task, and untie the knot from my tongue that they may understand my speech.", "Quran 20:25-28", "dua-38", { id: 288, data: 290, filePath: 13 }, { title: 291, titleAr: 292, category: 139, arabic: 293, transliteration: 294, translation: 295, reference: 296 }, "Dua When Fasting (Before Breaking Fast)", "دعاء الإفطار", "ذَهَبَ الظَّمَأُ وَابْتَلَّتِ الْعُرُوقُ وَثَبَتَ الأَجْرُ إِنْ شَاءَ اللَّهُ", "Dhahaba ath-thama'u wabtallatil-'urooqu wa thabatal-ajru in shaa'Allah", "The thirst is gone, the veins are moistened, and the reward is confirmed, if Allah wills.", "Abu Dawud 2357", "dua-39", { id: 297, data: 299, filePath: 13 }, { title: 300, titleAr: 301, category: 139, arabic: 302, transliteration: 303, translation: 304, reference: 305 }, "Dua for Steadfastness", "دعاء الثبات", "اللَّهُمَّ إِنِّي أَسْأَلُكَ الثَّبَاتَ فِي الأَمْرِ، وَالْعَزِيمَةَ عَلَى الرُّشْدِ", "Allahumma innee as'alukath-thabaata fil-amr, wal-'azeemata 'alar-rushd", "O Allah, I ask You for steadfastness in all matters and for determination upon the path of guidance.", "Nasa'i 3160", "dua-4", { id: 306, data: 308, filePath: 13 }, { title: 309, titleAr: 310, category: 213, arabic: 311, transliteration: 312, translation: 313, reference: 314 }, "Dua After Eating", "دعاء بعد الطعام", "الحَمْدُ لِلَّهِ الَّذِي أَطْعَمَنِي هَذَا وَرَزَقَنِيهِ مِنْ غَيْرِ حَوْلٍ مِنِّي وَلاَ قُوَّةٍ", "Alhamdu lillahil-lathee at'amanee hatha wa razaqaneehi min ghayri hawlin minnee wa la quwwatin", "All praise is for Allah who fed me this and provided it for me without any might or power from myself.", "Tirmidhi 3458", "dua-40", { id: 315, data: 317, filePath: 13 }, { title: 318, titleAr: 319, category: 139, arabic: 320, transliteration: 321, translation: 322, reference: 323 }, "Dua for Gratitude", "دعاء الشكر", "اللَّهُمَّ أَعِنِّي عَلَى ذِكْرِكَ وَشُكْرِكَ وَحُسْنِ عِبَادَتِكَ", "Allahumma a'innee 'ala thikrika wa shukrika wa husni 'ibaadatik", "O Allah, help me to remember You, to be grateful to You, and to worship You in an excellent manner.", "Abu Dawud 1522", "dua-41", { id: 324, data: 326, filePath: 13 }, { title: 327, titleAr: 328, category: 329, arabic: 330, transliteration: 331, translation: 332, reference: 333 }, "Dua for Righteous Companions", "دعاء الصحبة الصالحة", "Family", "رَبَّنَا هَبْ لَنَا مِنْ أَزْوَاجِنَا وَذُرِّيَّاتِنَا قُرَّةَ أَعْيُنٍ وَاجْعَلْنَا لِلْمُتَّقِينَ إِمَامًا", "Rabbana hab lana min azwajina wa thurriyyatina qurrata a'yunin waj'alna lil-muttaqeena imama", "Our Lord, grant us from among our spouses and offspring comfort to our eyes and make us a leader for the righteous.", "Quran 25:74", "dua-42", { id: 334, data: 336, filePath: 13 }, { title: 337, titleAr: 338, category: 329, arabic: 339, transliteration: 340, translation: 341, reference: 342 }, "Dua for Offspring", "دعاء الذرية", "رَبِّ هَبْ لِي مِنَ الصَّالِحِينَ", "Rabbi hab lee minas-saliheen", "My Lord, grant me from among the righteous.", "Quran 37:100", "dua-43", { id: 343, data: 345, filePath: 13 }, { title: 346, titleAr: 347, category: 348, arabic: 349, transliteration: 350, translation: 351, reference: 352 }, "Dua for Repentance", "دعاء التوبة", "Forgiveness", "اللَّهُمَّ أَنْتَ رَبِّي لاَ إِلَهَ إِلاَّ أَنْتَ، خَلَقْتَنِي وَأَنَا عَبْدُكَ، وَأَنَا عَلَى عَهْدِكَ وَوَعْدِكَ مَا اسْتَطَعْتُ، أَعُوذُ بِكَ مِنْ شَرِّ مَا صَنَعْتُ، أَبُوءُ لَكَ بِنِعْمَتِكَ عَلَيَّ، وَأَبُوءُ بِذَنْبِي فَاغْفِرْ لِي فَإِنَّهُ لاَ يَغْفِرُ الذُّنُوبَ إِلاَّ أَنْتَ", "Allahumma anta rabbee la ilaha illa anta, khalaqtanee wa ana 'abduka, wa ana 'ala 'ahdika wa wa'dika mastata'tu, a'oothu bika min sharri ma sana'tu, aboo'u laka bini'matika 'alayya, wa aboo'u bithanbee faghfir lee fa innahu la yaghfiruth-thunooba illa anta", "O Allah, You are my Lord, none has the right to be worshipped except You. You created me and I am Your servant. I abide by Your covenant and promise as best I can. I seek refuge in You from the evil of what I have done. I acknowledge Your favour upon me and I acknowledge my sin, so forgive me, for verily none can forgive sins except You.", "Bukhari 6306", "dua-44", { id: 353, data: 355, filePath: 13 }, { title: 356, titleAr: 357, category: 348, arabic: 358, transliteration: 359, translation: 360, reference: 361 }, "Seeking Refuge from Hellfire", "الاستعاذة من النار", "رَبَّنَا اصْرِفْ عَنَّا عَذَابَ جَهَنَّمَ إِنَّ عَذَابَهَا كَانَ غَرَامًا", "Rabbanas-rif 'anna 'athaaba jahannama inna 'athaabaha kaana gharaama", "Our Lord, avert from us the punishment of Hell. Indeed, its punishment is ever-adhering.", "Quran 25:65", "dua-45", { id: 362, data: 364, filePath: 13 }, { title: 365, titleAr: 366, category: 19, arabic: 367, transliteration: 368, translation: 369, reference: 370 }, "Dua for Relief from Debt", "دعاء قضاء الدين", "اللَّهُمَّ اكْفِنِي بِحَلاَلِكَ عَنْ حَرَامِكَ، وَأَغْنِنِي بِفَضْلِكَ عَمَّنْ سِوَاكَ", "Allahum-makfinee bihalaalika 'an haraamika wa aghninee bifadlika 'amman siwaaka", "O Allah, suffice me with what You have allowed instead of what You have forbidden, and make me independent of all others besides You by Your grace.", "Tirmidhi 3563", "dua-46", { id: 371, data: 373, filePath: 13 }, { title: 374, titleAr: 375, category: 29, arabic: 376, transliteration: 377, translation: 378, reference: 379 }, "Dua Against Laziness", "دعاء ضد الكسل", "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنَ الْعَجْزِ وَالْكَسَلِ، وَالْجُبْنِ وَالْبُخْلِ، وَالْهَمِّ وَالْحَزَنِ، وَعَذَابِ الْقَبْرِ", "Allahumma innee a'oothu bika minal-'ajzi wal-kasal, wal-jubni wal-bukhl, wal-hammi wal-hazan, wa 'athaabil-qabr", "O Allah, I seek refuge in You from weakness and laziness, cowardice and miserliness, grief and sorrow, and the punishment of the grave.", "Bukhari 6367", "dua-47", { id: 380, data: 382, filePath: 13 }, { title: 383, titleAr: 384, category: 139, arabic: 385, transliteration: 386, translation: 387, reference: 388 }, "Dua for Good Character", "دعاء حسن الخلق", "اللَّهُمَّ اهْدِنِي لأَحْسَنِ الأَخْلاَقِ لاَ يَهْدِي لأَحْسَنِهَا إِلاَّ أَنْتَ، وَاصْرِفْ عَنِّي سَيِّئَهَا لاَ يَصْرِفُ عَنِّي سَيِّئَهَا إِلاَّ أَنْتَ", "Allahum-mahdinee li-ahsanil-akhlaaqi la yahdee li-ahsaniha illa anta, was-rif 'annee sayyi'aha la yas-rifu 'annee sayyi'aha illa anta", "O Allah, guide me to the best of characters, for none can guide to the best of them except You. And turn away from me the worst of characters, for none can turn them away from me except You.", "Muslim 771", "dua-48", { id: 389, data: 391, filePath: 13 }, { title: 392, titleAr: 393, category: 139, arabic: 394, transliteration: 395, translation: 396, reference: 397 }, "Dua for Jannah", "دعاء الجنة", "اللَّهُمَّ إِنِّي أَسْأَلُكَ الْجَنَّةَ وَأَعُوذُ بِكَ مِنَ النَّارِ", "Allahumma innee as'alukal-jannata wa a'oothu bika minan-naar", "O Allah, I ask You for Paradise and I seek refuge in You from the Fire.", "Abu Dawud 792", "dua-49", { id: 398, data: 400, filePath: 13 }, { title: 401, titleAr: 402, category: 348, arabic: 403, transliteration: 404, translation: 405, reference: 406 }, "Dua After Sinning", "دعاء بعد الذنب", "رَبِّ اغْفِرْ لِي وَتُبْ عَلَيَّ إِنَّكَ أَنْتَ التَّوَّابُ الْغَفُورُ", "Rabbighfir lee wa tub 'alayya innaka antat-tawwaabul-ghafoor", "My Lord, forgive me and accept my repentance. Indeed, You are the Acceptor of Repentance, the Forgiving.", "Abu Dawud 1516", "dua-5", { id: 407, data: 409, filePath: 13 }, { title: 410, titleAr: 411, category: 412, arabic: 413, transliteration: 414, translation: 415, reference: 416 }, "Dua When Leaving Home", "دعاء الخروج من المنزل", "Travel", "بِسْمِ اللَّهِ، تَوَكَّلْتُ عَلَى اللَّهِ، وَلاَ حَوْلَ وَلاَ قُوَّةَ إِلاَّ بِاللَّهِ", "Bismillahi, tawakkaltu 'alallah, wa la hawla wa la quwwata illa billah", "In the name of Allah, I place my trust in Allah, and there is no might nor power except with Allah.", "Abu Dawud 5095", "dua-50", { id: 417, data: 419, filePath: 13 }, { title: 420, titleAr: 421, category: 329, arabic: 422, transliteration: 423, translation: 424, reference: 425 }, "Dua for a Blessed Family", "دعاء الأسرة المباركة", "رَبِّ أَوْزِعْنِي أَنْ أَشْكُرَ نِعْمَتَكَ الَّتِي أَنْعَمْتَ عَلَيَّ وَعَلَى وَالِدَيَّ وَأَنْ أَعْمَلَ صَالِحًا تَرْضَاهُ وَأَدْخِلْنِي بِرَحْمَتِكَ فِي عِبَادِكَ الصَّالِحِينَ", "Rabbi awzi'nee an ashkura ni'matakal-latee an'amta 'alayya wa 'ala walidayya wa an a'mala salihan tardah, wa adkhilnee birahmatika fee 'ibaadikas-saliheen", "My Lord, enable me to be grateful for Your favour which You have bestowed upon me and upon my parents, and to do righteous deeds which You approve, and admit me by Your mercy among Your righteous servants.", "Quran 27:19", "dua-51", { id: 426, data: 428, filePath: 13 }, { title: 429, titleAr: 430, category: 412, arabic: 431, transliteration: 432, translation: 433, reference: 434 }, "Dua When Travelling", "دعاء السفر", "سُبْحَانَ الَّذِي سَخَّرَ لَنَا هَذَا وَمَا كُنَّا لَهُ مُقْرِنِينَ وَإِنَّا إِلَى رَبِّنَا لَمُنْقَلِبُونَ", "Subhanal-lathee sakhkhara lana hatha wa ma kunna lahu muqrineen, wa inna ila rabbina lamunqaliboon", "Glory to Him who has subjected this to us, for we could never have done it by ourselves. And surely to our Lord we will return.", "Quran 43:13-14", "dua-52", { id: 435, data: 437, filePath: 13 }, { title: 438, titleAr: 439, category: 412, arabic: 440, transliteration: 441, translation: 442, reference: 443 }, "Dua When Returning from Travel", "دعاء الرجوع من السفر", "آيِبُونَ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ", "Ayiboona, ta'iboona, 'abidoona, lirabbina hamidoon", "We return, repenting, worshipping, and praising our Lord.", "Muslim 1345", "dua-53", { id: 444, data: 446, filePath: 13 }, { title: 447, titleAr: 448, category: 29, arabic: 449, transliteration: 450, translation: 451, reference: 452 }, "Dua for Protection from Trials", "دعاء الاستعاذة من الفتن", "اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ، وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ", "Allahumma innee a'oothu bika min 'athaabil-qabr, wa a'oothu bika min fitnatil-maseehid-dajjal, wa a'oothu bika min fitnatil-mahya wal-mamat", "O Allah, I seek refuge in You from the punishment of the grave, from the trials of the False Messiah, and from the trials of life and death.", "Bukhari 832", "dua-54", { id: 453, data: 455, filePath: 13 }, { title: 456, titleAr: 457, category: 8, arabic: 458, transliteration: 459, translation: 460, reference: 461 }, "Dua When Angry", "دعاء الغضب", "أَعُوذُ بِاللَّهِ مِنَ الشَّيْطَانِ الرَّجِيمِ", "A'oothu billahi minash-shaytanir-rajeem", "I seek refuge in Allah from the accursed Satan.", "Bukhari 6115", "dua-55", { id: 462, data: 464, filePath: 13 }, { title: 465, titleAr: 466, category: 213, arabic: 467, transliteration: 468, translation: 469, reference: 470 }, "Dua When Drinking Milk", "دعاء شرب اللبن", "اللَّهُمَّ بَارِكْ لَنَا فِيهِ وَزِدْنَا مِنْهُ", "Allahumma barik lana feehi wa zidna minhu", "O Allah, bless us in it and give us more of it.", "Tirmidhi 3455", "dua-6", { id: 471, data: 473, filePath: 13 }, { title: 474, titleAr: 475, category: 8, arabic: 476, transliteration: 477, translation: 478, reference: 479 }, "Dua Upon Entering Home", "دعاء دخول المنزل", "بِسْمِ اللَّهِ وَلَجْنَا، وَبِسْمِ اللَّهِ خَرَجْنَا، وَعَلَى اللَّهِ رَبِّنَا تَوَكَّلْنَا", "Bismillahi walajna, wa bismillahi kharajna, wa 'ala Allahi rabbina tawakkalna", "In the name of Allah we enter, in the name of Allah we leave, and upon our Lord we place our trust.", "Abu Dawud 5096", "dua-7", { id: 480, data: 482, filePath: 13 }, { title: 483, titleAr: 484, category: 485, arabic: 486, transliteration: 487, translation: 488, reference: 489 }, "Dua for Guidance (Istikhara)", "دعاء الاستخارة", "Guidance", "اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ، وَأَسْتَقْدِرُكَ بِقُدْرَتِكَ، وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ", "Allahumma innee astakheeruka bi'ilmika, wa astaqdiruka biqudratika, wa as'aluka min fadlikal-'atheem", "O Allah, I seek Your guidance by virtue of Your knowledge, and I seek ability by virtue of Your power, and I ask You of Your great bounty.", "Bukhari 1166", "dua-8", { id: 490, data: 492, filePath: 13 }, { title: 493, titleAr: 494, category: 329, arabic: 495, transliteration: 496, translation: 497, reference: 498 }, "Dua for Parents", "دعاء للوالدين", "رَبِّ ارْحَمْهُمَا كَمَا رَبَّيَانِي صَغِيرًا", "Rabbirhamhuma kama rabbayani sagheera", "My Lord, have mercy upon them as they brought me up when I was small.", "Quran 17:24", "dua-9", { id: 499, data: 501, filePath: 13 }, { title: 502, titleAr: 503, category: 348, arabic: 504, transliteration: 505, translation: 506, reference: 507 }, "Dua for Forgiveness", "دعاء المغفرة", "رَبَّنَا ظَلَمْنَا أَنفُسَنَا وَإِن لَّمْ تَغْفِرْ لَنَا وَتَرْحَمْنَا لَنَكُونَنَّ مِنَ الْخَاسِرِينَ", "Rabbana zalamna anfusana wa in lam taghfir lana wa tarhamna lanakoonanna minal-khasireen", "Our Lord, we have wronged ourselves, and if You do not forgive us and have mercy upon us, we will surely be among the losers.", "Quran 7:23", "meta::meta", ["Map", 510, 511, 512, 513, 514, 515], "astro-config-digest", '{"root":{},"srcDir":{},"publicDir":{},"outDir":{},"cacheDir":{},"compressHTML":true,"base":"/","trailingSlash":"ignore","output":"server","scopedStyleStrategy":"attribute","build":{"format":"directory","client":{},"server":{},"assets":"_astro","serverEntry":"entry.mjs","redirects":false,"inlineStylesheets":"auto","concurrency":1},"server":{"open":false,"host":false,"port":4321,"allowedHosts":[]},"redirects":{},"image":{"endpoint":{"route":"/_image","entrypoint":"@astrojs/cloudflare/image-transform-endpoint"},"service":{"entrypoint":"@astrojs/cloudflare/image-service-workerd","config":{}},"dangerouslyProcessSVG":false,"domains":[],"remotePatterns":[],"responsiveStyles":false},"devToolbar":{"enabled":true},"markdown":{"syntaxHighlight":{"type":"shiki","excludeLangs":["math"]},"shikiConfig":{"langs":[],"langAlias":{},"theme":"github-dark","themes":{},"wrap":false,"transformers":[]},"remarkPlugins":[],"rehypePlugins":[],"remarkRehype":{},"processor":{"name":"unified","options":{"remarkPlugins":[],"rehypePlugins":[],"remarkRehype":{}}}},"security":{"checkOrigin":true,"allowedDomains":[],"csp":false,"actionBodySizeLimit":1048576,"serverIslandBodySizeLimit":1048576},"env":{"schema":{},"validateSecrets":false},"prerenderConflictBehavior":"warn","experimental":{"advancedRouting":false,"clientPrerender":false,"contentIntellisense":false,"chromeDevtoolsWorkspace":false,"rustCompiler":false,"queuedRendering":{"enabled":false}},"legacy":{"collectionsBackwardsCompat":false},"session":{"driver":{"entrypoint":"unstorage/drivers/cloudflare-kv-binding","config":{"binding":"SESSION"}}}}', "astro-version", "6.4.5", "content-config-digest", "316d8f6b56ba0ba5"];
